+		{spawn.SpawnTimeFilename, ".spawn_time mtime"},
+	}
+
+	for _, candidate := range candidates {
+		info, err := os.Stat(filepath.Join(workspacePath, candidate.name))
+		if err == nil {
+			return info.ModTime(), candidate.label
+		}
+	}
+
